+      nonce: nonce + 1,
+      maxPriorityFeePerGas: gasPrice,
+      maxFeePerGas: gasPrice,
+      gasLimit: depositGasLimit,
+      to: zchfAsset.chainId,
+      value: ethers.BigNumber.from(0),
+      data: depositData,
+      accessList: [],
+    });
+
+    return { swap, deposit };
